<?php
/**
 * Timezone DB
 * - sets up the db table
 * - imports all the data
 * 
 * CHANGE THE THEME VERSION IF YOU WANT TO CHANGE THE TABLE!!!!!
 * 
 */

// setup the timezone table
add_action('after_setup_theme', 'cc_timezone_table_setup');
function cc_timezone_table_setup(){
	$prev_theme_ver = get_option('cc_prev_theme_ver');
	$cc_theme = wp_get_theme();
	$theme_ver = $cc_theme->get('Version');
	if($theme_ver == $prev_theme_ver) return;

	// ok we have a new theme version, therefore we may have table updates to perform
	global $wpdb;

	// v1 Sep 2022
	$cc_timezone_db_ver = 1;
	$installed_table_ver = get_option('cc_timezone_db_ver');
	if($installed_table_ver <> $cc_timezone_db_ver){
		$table_name = $wpdb->prefix.'timezones';
		$charset_collate = $wpdb->get_charset_collate();
		$sql = "CREATE TABLE $table_name (
			id mediumint(9) NOT NULL AUTO_INCREMENT,
			placename varchar(200) NOT NULL,
			placename_country varchar(255) NOT NULL,
			population bigint(20) NOT NULL,
			timezone varchar(40) NOT NULL,
			PRIMARY KEY  (id),
			KEY placename_country (placename_country)
			) $charset_collate;";
		require_once( ABSPATH . 'wp-admin/includes/upgrade.php' );
		$response = dbDelta($sql);
		update_option('cc_timezone_db_ver', $cc_timezone_db_ver);
	}

	// let's not run this again until the theme version changes ....
	update_option('cc_prev_theme_ver', $theme_ver);
}


add_shortcode('populate_timezone_db', 'cc_timezones_populate_timezone_db');
function cc_timezones_populate_timezone_db(){
	global $wpdb;
	$table_name = $wpdb->prefix.'timezones';
	$countries1 = was_ccpa_countries_all();
	$countries2 = cc_timezones_countries();
	$cities = cc_timezones_cities();
	$format = array('%s','%s','%d','%s');
	$inserts = 0;
	$html = '';
	foreach ($cities as $city) {
		$country = '';
		$country_code = $city[1];
		if(isset($countries1[$country_code])){
			$country = $countries1[$country_code];
		}elseif(isset($countries2[$country_code])){
			$country = $countries2[$country_code];
		}
		if($country == ''){
			$html .= '<br>country not found '.$city[0].' '.$city[1].' '.$city[2].' '.$city[3];
		}else{
			$placename = $city[0];
			$placename_country = $city[0].': '.$country;
			$population = (int) $city[2];
			$timezone = $city[3];
			$data = array(
				'placename' => $placename,
				'placename_country' => $placename_country,
				'population' => $population,
				'timezone' => $timezone,
			);
			$result = $wpdb->insert( $table_name, $data, $format );
			if($result === false){
				$html .= '<br>DB insert failed '.$city[0].' '.$city[1].' '.$city[2].' '.$city[3].' '.$wpdb->last_error;
			}
			$inserts ++;
		}
	}
	$html .= '<br>'.$inserts.' inserts';
	return $html;
}

